from flask import Flask, request, jsonify
from pymongo import MongoClient
from pymongo.errors import PyMongoError
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
MONGO_DB = os.getenv("MONGO_DB", "testdb")
MONGO_COLLECTION = os.getenv("MONGO_COLLECTION", "documents")

client = MongoClient(MONGO_URI)
db = client[MONGO_DB]
collection = db[MONGO_COLLECTION]

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/filter", methods=["POST"])
def filter_documents():
    data = request.get_json(silent=True) or {}
    where_expression = data.get("filter")

    if not isinstance(where_expression, str) or not where_expression.strip():
        return jsonify({"error": "A non-empty string 'filter' is required"}), 400

    limit = data.get("limit", 100)
    try:
        limit = max(1, min(int(limit), 1000))
    except (TypeError, ValueError):
        return jsonify({"error": "'limit' must be an integer"}), 400

    projection = data.get("projection")
    if projection is not None and not isinstance(projection, dict):
        return jsonify({"error": "'projection' must be an object if provided"}), 400

    try:
        cursor = collection.find({"$where": where_expression}, projection).limit(limit)
        results = []
        for doc in cursor:
            doc["_id"] = str(doc["_id"])
            results.append(doc)
        return jsonify({"count": len(results), "results": results})
    except PyMongoError as e:
        return jsonify({"error": str(e)}), 500

@app.route("/insert-sample", methods=["POST"])
def insert_sample():
    data = request.get_json(silent=True)
    if isinstance(data, list):
        result = collection.insert_many(data)
        return jsonify({"inserted_ids": [str(_id) for _id in result.inserted_ids]})
    if isinstance(data, dict):
        result = collection.insert_one(data)
        return jsonify({"inserted_id": str(result.inserted_id)})
    return jsonify({"error": "Request body must be a JSON object or array"}), 400

